chapters.code:
/* 文字 */
color: red;               /* 文字颜色 */
font-size: 18px;          /* 字体大小 */
font-weight: bold;        /* 加粗 */
text-align: center;       /* 居中 */

/* 背景 */
background-color: #f0f0f0;
background: url('图片.jpg');

/* 间距 */
margin: 20px;             /* 外边距（元素和外面的距离） */
padding: 10px;            /* 内边距（内容和边框的距离） */

/* 边框 */
border: 1px solid #ccc;   /* 粗细 样式 颜色 */
border-radius: 8px;       /* 圆角 */

/* 尺寸 */
width: 300px;
height: 200px;

.box {
    width: 200px;
    height: 100px;
    padding: 20px;         /* 四边都是20px */
    border: 2px solid red;
    margin: 30px auto;     /* 上下30px，左右auto（水平居中）*/
    background: #e0f7fa;
    /* 推荐加这个，让宽高包含padding和border */
    box-sizing: border-box;
}

.container {
    display: flex;              /* 开启 flex 布局 */
    flex-direction: row;        /* 横向排列（默认） */
    justify-content: center;    /* 主轴居中 */
    align-items: center;        /* 交叉轴居中 */
    gap: 20px;                  /* 子元素间距 */
    flex-wrap: wrap;            /* 自动换行 */
}

/* 子元素 */
.item {
    flex: 1;    /* 平均分配剩余空间 */
    min-width: 200px;
}
